def keys(self):  
    """
    Restituisce le chiavi del record.  

    :return: lista dei nomi delle chiavi  
    """
    return list(self.record.keys())

def values(self, *keys):
    """
    Restituisce i valori del record, con la possibilità di filtrare per includere solo determinati valori in base all'indice o alla chiave.

    :param keys: indici o chiavi degli elementi da includere; se non viene fornito nessun parametro, verranno inclusi tutti i valori  
    :return: lista di valori  
    :rtype: list
    """
    if not keys:
        return list(self.record.values())

    valori_filtrati = []
    for chiave in keys:
        if chiave in self.record:
            valori_filtrati.append(self.record[chiave])

    return valori_filtrati

def data(self, *chiavi):
    """
    Restituisce le chiavi e i valori di questo record come un dizionario, includendo opzionalmente solo determinati valori in base all'indice o alla chiave. Le chiavi fornite negli elementi che non sono presenti nel record verranno inserite con un valore di :const:`None`; gli indici forniti che sono fuori dai limiti genereranno un'eccezione :exc:`IndexError`.

    :param chiavi: indici o chiavi degli elementi da includere; se non ne vengono forniti, verranno inclusi tutti i valori  
    :return: dizionario dei valori, indicizzati per nome del campo  
    :raises: :exc:`IndexError` se viene specificato un indice fuori dai limiti  
    """
    dizionario = {}
    for chiave in chiavi:
        if isinstance(chiave, int):
            if chiave < 0 or chiave >= len(self):
                raise IndexError("Indice fuori dai limiti")
            dizionario[self.nome_campo(chiave)] = self.valore(chiave)
        else:
            dizionario[chiave] = getattr(self, chiave, None)

    if not chiavi:
        for i in range(len(self)):
            dizionario[self.nome_campo(i)] = self.valore(i)

    return dizionario

def parse_version(s: str) -> tuple[int, ...]:
    """versione semplificata per il confronto delle versioni"""
    return tuple(int(part) for part in s.split('.'))

import time
from collections import OrderedDict
from functools import wraps

def ttl_cache(maxsize=128, ttl=600, timer=time.monotonic, typed=False):
    """
    Decorator per racchiudere una funzione con un oggetto callable di memorizzazione (memoization) che salva fino a `maxsize` risultati basandosi su un algoritmo Least Recently Used (LRU) con un valore di time-to-live (TTL) per ogni elemento.
    """
    class Cache:
        def __init__(self, maxsize, ttl):
            self.maxsize = maxsize
            self.ttl = ttl
            self.cache = OrderedDict()
            self.timestamps = {}

        def __getitem__(self, key):
            if key in self.cache:
                if (timer() - self.timestamps[key]) < self.ttl:
                    self.cache.move_to_end(key)
                    return self.cache[key]
                else:
                    self.cache.pop(key)
                    self.timestamps.pop(key)
            raise KeyError(key)

        def __setitem__(self, key, value):
            if key in self.cache:
                self.cache.move_to_end(key)
            self.cache[key] = value
            self.timestamps[key] = timer()
            if len(self.cache) > self.maxsize:
                self.cache.popitem(last=False)
                self.timestamps.popitem(last=False)

    cache = Cache(maxsize, ttl)

    @wraps
    def decorator(funzione):
        def wrapper(*args, **kwargs):
            chiave = args if not typed else (type(arg) for arg in args)
            try:
                return cache[chiave]
            except KeyError:
                risultato = funzione(*args, **kwargs)
                cache[chiave] = risultato
                return risultato
        return wrapper

    return decorator

def mru_cache(maxsize=128, typed=False):
    """
    Decorator per racchiudere una funzione con un oggetto richiamabile che memorizza
    fino a `maxsize` risultati basandosi su un algoritmo di tipo Most Recently Used (MRU).
    """
    from collections import OrderedDict
    from functools import wraps

    class Cache:
        def __init__(self, maxsize):
            self.maxsize = maxsize
            self.cache = OrderedDict()

        def __call__(self, key):
            if key in self.cache:
                self.cache.move_to_end(key)
                return self.cache[key]
            return None

        def __setitem__(self, key, value):
            if key in self.cache:
                self.cache.move_to_end(key)
            self.cache[key] = value
            if len(self.cache) > self.maxsize:
                self.cache.popitem(last=False)

    def decorator(funzione):
        cache = Cache(maxsize)

        @wraps(funzione)
        def wrapper(*args, **kwargs):
            chiave = args if not typed else (type(arg) for arg in args)
            risultato = cache[chiave]
            if risultato is None:
                risultato = funzione(*args, **kwargs)
                cache[chiave] = risultato
            return risultato

        return wrapper

    return decorator

def lfu_cache(maxsize=128, typed=False):
    """
    Decorator per racchiudere una funzione con un oggetto callable di memoizzazione
    che salva fino a `maxsize` risultati basandosi su un algoritmo Least Frequently Used (LFU).
    """
    from collections import defaultdict, OrderedDict
    import functools

    class LFUCache:
        def __init__(self, maxsize):
            self.maxsize = maxsize
            self.cache = {}
            self.freq = defaultdict(OrderedDict)
            self.min_freq = 0

        def get(self, key):
            if key not in self.cache:
                return None
            value, freq = self.cache[key]
            del self.freq[freq][key]
            if not self.freq[freq]:
                del self.freq[freq]
                if self.min_freq == freq:
                    self.min_freq += 1
            self.freq[freq + 1][key] = value
            self.cache[key] = (value, freq + 1)
            return value

        def put(self, key, value):
            if key in self.cache:
                self.get(key)  # Aggiorna la frequenza
                self.cache[key] = (value, self.cache[key][1])
                return
            if len(self.cache) >= self.maxsize:
                evict_key, _ = self.freq[self.min_freq].popitem(last=False)
                del self.cache[evict_key]
            self.cache[key] = (value, 1)
            self.freq[1][key] = value
            self.min_freq = 1

    def decorator(func):
        cache = LFUCache(maxsize)

        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            if typed:
                key = (args, frozenset(kwargs.items()))
            else:
                key = (tuple(args), frozenset((k, v) for k, v in kwargs.items()))
            result = cache.get(key)
            if result is None:
                result = func(*args, **kwargs)
                cache.put(key, result)
            return result

        return wrapper

    return decorator

def get(self, chiave, predefinito=None):
    """
    `D.get(k[, d]) -> D[k]` se `k` è presente in `D`, altrimenti `d`. Il valore predefinito di `d` è `None`.
    """
    if chiave in self:
        return self[chiave]
    else:
        return predefinito

