def generate_default_observer_schema_dict(manifest_dict, first_level=False):
    """
    Insieme alla funzione :func:`generate_default_observer_schema_list`, questa funzione viene chiamata ricorsivamente per generare una parte dello schema predefinito `observer_schema` a partire da una risorsa Kubernetes, definita rispettivamente da `manifest_dict` o `manifest_list`.

    ### Argomenti:
    - **manifest_dict (dict)**: Risorse Kubernetes parziali.
    - **first_level (bool, opzionale)**: Se impostato su True, indica che il dizionario rappresenta l'intero schema `observer_schema` di una risorsa Kubernetes.

    ### Ritorna:
    - **dict**: Lo schema parziale `observer_schema` generato.

    Questa funzione crea un nuovo dizionario a partire da `manifest_dict` e sostituisce tutti i valori che non sono liste o dizionari con `None`.

    Nel caso di un dizionario `first_level` (ovvero lo schema completo `observer_schema` per una risorsa), i valori dei campi identificativi vengono copiati dal file manifest.
    """
    schema_dict = {}

    for chiave, valore in manifest_dict.items():
        if isinstance(valore, dict):
            schema_dict[chiave] = generate_default_observer_schema_dict(valore, first_level)
        elif isinstance(valore, list):
            schema_dict[chiave] = [generate_default_observer_schema_dict(item, first_level) if isinstance(item, dict) else None for item in valore]
        else:
            if first_level and chiave in ['name', 'namespace', 'kind', 'apiVersion']:
                schema_dict[chiave] = valore
            else:
                schema_dict[chiave] = None

    return schema_dict

def update_last_applied_manifest_dict_from_resp(
    last_applied_manifest, observer_schema, response
):
    """
    Insieme alla funzione :func:``update_last_applied_manifest_list_from_resp``, 
    questa funzione viene chiamata ricorsivamente per aggiornare un 
    ``last_applied_manifest`` parziale a partire da una risposta parziale di Kubernetes.

    Argomenti:
        last_applied_manifest (dict): ``last_applied_manifest`` parziale in fase di aggiornamento
        observer_schema (dict): ``observer_schema`` parziale
        response (dict): risposta parziale dall'API di Kubernetes.

    Eccezioni:
        KeyError: Se il campo osservato non è presente nella risposta di Kubernetes.

    Questa funzione analizza tutti i campi osservati e inizializza il loro valore 
    in ``last_applied_manifest`` se non sono ancora presenti.
    """
    for chiave, valore in observer_schema.items():
        if isinstance(valore, dict):
            # Se il valore è un dizionario, chiama ricorsivamente la funzione
            if chiave not in last_applied_manifest:
                last_applied_manifest[chiave] = {}
            update_last_applied_manifest_dict_from_resp(
                last_applied_manifest[chiave], valore, response.get(chiave, {})
            )
        else:
            # Se il valore non è un dizionario, controlla se è presente nella risposta
            if chiave not in last_applied_manifest:
                if chiave not in response:
                    raise KeyError(f"Il campo '{chiave}' non è presente nella risposta di Kubernetes.")
                last_applied_manifest[chiave] = response[chiave]

def generate_default_observer_schema(app):
    """
    Genera lo schema di osservazione predefinito per ogni risorsa Kubernetes presente in
    ``spec.manifest`` per la quale non è stato specificato uno schema di osservazione personalizzato.

    Argomenti:
        app (krake.data.kubernetes.Application): L'applicazione per la quale generare uno
            schema di osservazione predefinito.
    """
    schema_predefinito = {}
    risorse = app.spec.manifest

    for risorsa in risorse:
        if 'schema_osservazione' not in risorsa:
            schema_predefinito[risorsa['nome']] = {
                'tipo': risorsa['tipo'],
                'osservazione': 'predefinito'
            }

    return schema_predefinito
